// src/components/article/TableManager.jsx
import React, { useState, useEffect } from 'react';

const TableManager = ({ isOpen, onClose, onSave, editingBlock, tableCounter }) => {
  const [rows, setRows] = useState(3);
  const [cols, setCols] = useState(3);
  const [caption, setCaption] = useState('');
  const [headers, setHeaders] = useState([]);
  const [tableData, setTableData] = useState([]);
  const [mergedCells, setMergedCells] = useState({});
  const [rotatedCells, setRotatedCells] = useState({});
  const [selectedCell, setSelectedCell] = useState(null);
  const [mergeMode, setMergeMode] = useState(false);
  const [rotateMode, setRotateMode] = useState(false);
  
  // Загрузка данных при редактировании
  useEffect(() => {
    if (editingBlock) {
      setRows(editingBlock.data?.length || 3);
      setCols(editingBlock.data?.[0]?.length || 3);
      setCaption(editingBlock.caption || '');
      setHeaders(editingBlock.headers || Array(editingBlock.data?.[0]?.length || 3).fill(''));
      setTableData(editingBlock.data || Array(3).fill().map(() => Array(3).fill('')));
      setMergedCells(editingBlock.mergedCells || {});
      setRotatedCells(editingBlock.rotatedCells || {});
    } else {
      setRows(3);
      setCols(3);
      setCaption('');
      setHeaders(Array(3).fill(''));
      setTableData(Array(3).fill().map(() => Array(3).fill('')));
      setMergedCells({});
      setRotatedCells({});
    }
  }, [editingBlock]);
  
  // Обновление размеров таблицы
  useEffect(() => {
    if (!editingBlock) {
      const newHeaders = [...headers];
      const newData = [...tableData];
      
      // Изменяем количество строк
      if (newData.length !== rows) {
        if (newData.length < rows) {
          for (let i = newData.length; i < rows; i++) {
            newData.push(Array(cols).fill(''));
          }
        } else {
          newData.length = rows;
        }
      }
      
      // Изменяем количество столбцов
      if (newHeaders.length !== cols) {
        if (newHeaders.length < cols) {
          for (let i = newHeaders.length; i < cols; i++) {
            newHeaders.push('');
            newData.forEach(row => row.push(''));
          }
        } else {
          newHeaders.length = cols;
          newData.forEach(row => row.length = cols);
        }
      }
      
      setHeaders(newHeaders);
      setTableData(newData);
    }
  }, [rows, cols, editingBlock]);
  
  if (!isOpen) return null;
  
  // Получение реальных координат с учетом объединения
  const getActualCell = (row, col) => {
    for (const [key, info] of Object.entries(mergedCells)) {
      const [startRow, startCol] = key.split('-').map(Number);
      if (row >= startRow && row < startRow + info.rowspan &&
          col >= startCol && col < startCol + info.colspan) {
        return { row: startRow, col: startCol, merged: true, info };
      }
    }
    return { row, col, merged: false };
  };
  
  // Проверка, нужно ли рендерить ячейку
  const shouldRenderCell = (row, col) => {
    const actual = getActualCell(row, col);
    if (actual.merged) {
      return actual.row === row && actual.col === col;
    }
    return true;
  };
  
  // Получение значения ячейки
  const getCellValue = (row, col) => {
    const actual = getActualCell(row, col);
    if (actual.merged) {
      const key = `${actual.row}-${actual.col}`;
      return mergedCells[key]?.value || '';
    }
    if (row === 0) {
      return headers[col] || '';
    }
    return tableData[row - 1]?.[col] || '';
  };
  
  // Обновление значения ячейки
  const updateCellValue = (row, col, value) => {
    const actual = getActualCell(row, col);
    if (actual.merged) {
      const key = `${actual.row}-${actual.col}`;
      setMergedCells({
        ...mergedCells,
        [key]: { ...mergedCells[key], value }
      });
    } else if (row === 0) {
      const newHeaders = [...headers];
      newHeaders[col] = value;
      setHeaders(newHeaders);
    } else {
      const newData = [...tableData];
      newData[row - 1][col] = value;
      setTableData(newData);
    }
  };
  
  // Объединение ячеек
  const mergeCells = () => {
    if (!selectedCell) return;
    setMergeMode(true);
  };
  
  const completeMerge = (endRow, endCol) => {
    if (!selectedCell || !mergeMode) return;
    
    const [startRow, startCol] = selectedCell;
    const rowspan = endRow - startRow + 1;
    const colspan = endCol - startCol + 1;
    const key = `${startRow}-${startCol}`;
    
    const newMergedCells = { ...mergedCells };
    newMergedCells[key] = {
      rowspan,
      colspan,
      value: getCellValue(startRow, startCol)
    };
    
    setMergedCells(newMergedCells);
    setMergeMode(false);
    setSelectedCell(null);
  };
  
  // Поворот ячейки
  const toggleRotate = (row, col) => {
    const actual = getActualCell(row, col);
    const key = `${actual.row}-${actual.col}`;
    const newRotatedCells = { ...rotatedCells };
    if (newRotatedCells[key]) {
      delete newRotatedCells[key];
    } else {
      newRotatedCells[key] = true;
    }
    setRotatedCells(newRotatedCells);
  };
  
  const handleSave = () => {
    // Создаем данные для сохранения
    const data = [];
    for (let i = 1; i <= rows; i++) {
      const row = [];
      for (let j = 0; j < cols; j++) {
        row.push(getCellValue(i, j));
      }
      data.push(row);
    }
    
    onSave({
      caption: caption.trim() || `Таблица ${tableCounter}`,
      headers: headers,
      data: data,
      mergedCells: mergedCells,
      rotatedCells: rotatedCells
    });
  };
  
  const styles = {
    overlay: {
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0, 0, 0, 0.5)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 1000
    },
    modal: {
      backgroundColor: 'white',
      padding: '30px',
      borderRadius: '15px',
      width: '90%',
      maxWidth: '1200px',
      maxHeight: '90vh',
      overflow: 'auto',
      boxShadow: '0 10px 30px rgba(0,0,0,0.2)'
    },
    title: {
      fontSize: '24px',
      fontWeight: 'bold',
      marginBottom: '20px',
      color: '#e67e22',
      textAlign: 'center'
    },
    formGroup: {
      marginBottom: '20px'
    },
    label: {
      display: 'block',
      marginBottom: '8px',
      fontWeight: 'bold',
      color: '#333'
    },
    input: {
      width: '100%',
      padding: '10px',
      border: '1px solid #ddd',
      borderRadius: '8px',
      fontSize: '14px'
    },
    controlsContainer: {
      display: 'flex',
      gap: '15px',
      marginBottom: '20px',
      flexWrap: 'wrap'
    },
    sizeControl: {
      display: 'flex',
      gap: '10px',
      alignItems: 'center'
    },
    sizeInput: {
      width: '80px',
      padding: '8px',
      border: '1px solid #ddd',
      borderRadius: '5px'
    },
    actionButton: {
      padding: '8px 16px',
      backgroundColor: '#3498db',
      color: 'white',
      border: 'none',
      borderRadius: '5px',
      cursor: 'pointer',
      fontSize: '14px'
    },
    actionButtonActive: {
      padding: '8px 16px',
      backgroundColor: '#e67e22',
      color: 'white',
      border: 'none',
      borderRadius: '5px',
      cursor: 'pointer',
      fontSize: '14px'
    },
    tableContainer: {
      overflowX: 'auto',
      marginBottom: '20px',
      border: '1px solid #ddd',
      borderRadius: '8px'
    },
    table: {
      borderCollapse: 'collapse',
      width: '100%',
      minWidth: '500px'
    },
    th: {
      border: '1px solid #ddd',
      padding: '8px',
      textAlign: 'center',
      backgroundColor: '#f8f9fa',
      fontWeight: 'bold',
      position: 'relative'
    },
    td: {
      border: '1px solid #ddd',
      padding: '8px',
      textAlign: 'center',
      position: 'relative'
    },
    rotatedCell: {
      writingMode: 'vertical-rl',
      textOrientation: 'mixed',
      whiteSpace: 'nowrap',
      height: '60px'
    },
    cellInput: {
      width: '100%',
      border: 'none',
      textAlign: 'center',
      fontSize: '14px',
      padding: '4px',
      backgroundColor: 'transparent'
    },
    selectedCell: {
      backgroundColor: '#fff3e0',
      outline: '2px solid #f39c12'
    },
    mergeArea: {
      backgroundColor: '#e8f4fd',
      outline: '2px dashed #3498db'
    },
    rotateButton: {
      position: 'absolute',
      top: '-10px',
      right: '-10px',
      width: '20px',
      height: '20px',
      borderRadius: '50%',
      backgroundColor: '#2ecc71',
      color: 'white',
      border: 'none',
      cursor: 'pointer',
      fontSize: '12px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    },
    buttonContainer: {
      display: 'flex',
      gap: '10px',
      marginTop: '20px'
    },
    saveButton: {
      flex: 1,
      padding: '12px',
      backgroundColor: '#f39c12',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontSize: '16px',
      fontWeight: 'bold'
    },
    cancelButton: {
      flex: 1,
      padding: '12px',
      backgroundColor: '#95a5a6',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontSize: '16px',
      fontWeight: 'bold'
    }
  };
  
  return (
    <div style={styles.overlay} onClick={onClose}>
      <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
        <h3 style={styles.title}>
          {editingBlock ? '✏️ Редактировать таблицу' : '📊 Создать таблицу'}
        </h3>
        
        <div style={styles.formGroup}>
          <label style={styles.label}>Название таблицы:</label>
          <input
            type="text"
            value={caption}
            onChange={(e) => setCaption(e.target.value)}
            placeholder="Например: Сравнительный анализ"
            style={styles.input}
          />
        </div>
        
        <div style={styles.controlsContainer}>
          <div style={styles.sizeControl}>
            <label>Строки:</label>
            <input
              type="number"
              min="1"
              max="20"
              value={rows}
              onChange={(e) => setRows(parseInt(e.target.value) || 1)}
              style={styles.sizeInput}
            />
          </div>
          <div style={styles.sizeControl}>
            <label>Столбцы:</label>
            <input
              type="number"
              min="1"
              max="20"
              value={cols}
              onChange={(e) => setCols(parseInt(e.target.value) || 1)}
              style={styles.sizeInput}
            />
          </div>
          <button
            onClick={mergeCells}
            style={mergeMode ? styles.actionButtonActive : styles.actionButton}
          >
            🔗 Объединить ячейки
          </button>
          {mergeMode && (
            <span style={{ color: '#e67e22', fontSize: '14px' }}>
              Выберите конечную ячейку для объединения
            </span>
          )}
        </div>
        
        <div style={styles.tableContainer}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}></th>
                {Array(cols).fill().map((_, colIndex) => (
                  <th key={colIndex} style={styles.th}>
                    {String.fromCharCode(65 + colIndex)}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {Array(rows + 1).fill().map((_, rowIndex) => {
                if (rowIndex === 0) {
                  return (
                    <tr key="headers">
                      <td style={styles.td}><strong>Заголовки</strong></td>
                      {Array(cols).fill().map((_, colIndex) => {
                        if (!shouldRenderCell(0, colIndex)) return null;
                        const actual = getActualCell(0, colIndex);
                        const rowSpan = actual.merged ? actual.info.rowspan : 1;
                        const colSpan = actual.merged ? actual.info.colspan : 1;
                        const isSelected = selectedCell && selectedCell[0] === 0 && selectedCell[1] === colIndex;
                        const isRotated = rotatedCells[`${actual.row}-${actual.col}`];
                        
                        return (
                          <td
                            key={colIndex}
                            rowSpan={rowSpan}
                            colSpan={colSpan}
                            style={{
                              ...styles.td,
                              ...(isSelected && styles.selectedCell),
                              ...(mergeMode && isSelected && styles.mergeArea),
                              ...(isRotated && styles.rotatedCell)
                            }}
                            onClick={() => {
                              if (mergeMode && selectedCell) {
                                completeMerge(0, colIndex);
                              } else {
                                setSelectedCell([0, colIndex]);
                              }
                            }}
                          >
                            <input
                              type="text"
                              value={getCellValue(0, colIndex)}
                              onChange={(e) => updateCellValue(0, colIndex, e.target.value)}
                              style={styles.cellInput}
                            />
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                toggleRotate(0, colIndex);
                              }}
                              style={styles.rotateButton}
                              title="Повернуть текст"
                            >
                              ↻
                            </button>
                          </td>
                        );
                      })}
                    </tr>
                  );
                }
                
                const dataRowIndex = rowIndex - 1;
                return (
                  <tr key={dataRowIndex}>
                    <td style={styles.td}>
                      <strong>{dataRowIndex + 1}</strong>
                    </td>
                    {Array(cols).fill().map((_, colIndex) => {
                      if (!shouldRenderCell(dataRowIndex + 1, colIndex)) return null;
                      const actual = getActualCell(dataRowIndex + 1, colIndex);
                      const rowSpan = actual.merged ? actual.info.rowspan : 1;
                      const colSpan = actual.merged ? actual.info.colspan : 1;
                      const isSelected = selectedCell && selectedCell[0] === dataRowIndex + 1 && selectedCell[1] === colIndex;
                      const isRotated = rotatedCells[`${actual.row}-${actual.col}`];
                      
                      return (
                        <td
                          key={colIndex}
                          rowSpan={rowSpan}
                          colSpan={colSpan}
                          style={{
                            ...styles.td,
                            ...(isSelected && styles.selectedCell),
                            ...(mergeMode && isSelected && styles.mergeArea),
                            ...(isRotated && styles.rotatedCell)
                          }}
                          onClick={() => {
                            if (mergeMode && selectedCell) {
                              completeMerge(dataRowIndex + 1, colIndex);
                            } else {
                              setSelectedCell([dataRowIndex + 1, colIndex]);
                            }
                          }}
                        >
                          <input
                            type="text"
                            value={getCellValue(dataRowIndex + 1, colIndex)}
                            onChange={(e) => updateCellValue(dataRowIndex + 1, colIndex, e.target.value)}
                            style={styles.cellInput}
                          />
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              toggleRotate(dataRowIndex + 1, colIndex);
                            }}
                            style={styles.rotateButton}
                            title="Повернуть текст"
                          >
                            ↻
                          </button>
                        </td>
                      );
                    })}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        
        {mergeMode && (
          <div style={{ textAlign: 'center', marginBottom: '10px', color: '#e67e22' }}>
            Режим объединения: выберите ячейку для завершения объединения
            <button
              onClick={() => {
                setMergeMode(false);
                setSelectedCell(null);
              }}
              style={{ marginLeft: '10px', padding: '4px 10px', backgroundColor: '#e74c3c', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
            >
              Отменить
            </button>
          </div>
        )}
        
        <div style={styles.buttonContainer}>
          <button onClick={handleSave} style={styles.saveButton}>
            {editingBlock ? '💾 Сохранить изменения' : '➕ Создать таблицу'}
          </button>
          <button onClick={onClose} style={styles.cancelButton}>
            ✕ Отмена
          </button>
        </div>
      </div>
    </div>
  );
};

export default TableManager;
